/// <summary>
/// Determines whether the <paramref name="_fieldIdToCheck" /> field is valid.
/// </summary>
/// <param name="field">
/// The field ID of the field to validate.
/// </param>
/// <returns>
/// true if the field is valid; otherwise, false.
/// </returns>
public boolean validateField(FieldId field)
{
    boolean isValid = next validateField(field);

    if(isValid)
    {
        switch(field)
        {
            case fieldNum(PurchParmTable, ETG_BLnumber):
                if(this.ETG_BLnumber && this.Ordering != DocumentStatus::Invoice)
                {
                    isValid = ETGBLNumberUniqueValidation::checkBLNum(this.ETG_BLnumber, this.DataAreaId, ModuleSalesPurch::Purch, this.PurchId);
                }
                break;
        }
    }

    return isValid;
}

public boolean validateWrite()
{
    Boolean isValid = next validateWrite();

    if (isValid)
    {
        if(this.ETG_BLnumber && this.Ordering != DocumentStatus::Invoice)
        {
            isValid = ETGBLNumberUniqueValidation::checkBLNum(this.ETG_BLnumber, this.DataAreaId, ModuleSalesPurch::Purch, this.PurchId);
        }
    }

    return isValid;
}
